#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[12346];
        scanf("%s", s);
        int n = strlen(s);
        int i = 0, j = n - 1;
        int flag = 1;
        while (i < j) {
            if (s[i] == s[j]) {
                i++;
                j--;
            } else if (s[i] == '.') {
                s[i] = s[j];
                i++;
                j--;
            } else if (s[j] == '.') {
                s[j] = s[i];
                i++;
                j--;
            } else {
                flag = 0;
                break;
            }
        }
        if (flag) {
            printf("%s\n", s);
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

