import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String s = sc.nextLine();
            int n = s.length();
            int i = 0, j = n - 1;
            int flag = 1;
            char[] arr = s.toCharArray();
            while (i < j) {
                if (arr[i] == arr[j]) {
                    i++;
                    j--;
                } else if (arr[i] == '.') {
                    arr[i] = arr[j];
                    i++;
                    j--;
                } else if (arr[j] == '.') {
                    arr[j] = arr[i];
                    i++;
                    j--;
                } else {
                    flag = 0;
                    break;
                }
            }
            if (flag) {
                System.out.println(new String(arr));
            } else {
                System.out.println(-1);
            }
        }
    }
}

